const data = $json;
const messaging = data.body?.entry?.[0]?.messaging?.[0] || data.entry?.[0]?.messaging?.[0] || data;

const page_id = data.id || data.recipient?.id || messaging.recipient?.id || '';
const sender_id = messaging.sender?.id || data.sender?.id || data.from?.id || '';
const recipient_id = messaging.recipient?.id || data.recipient?.id || '';
const message_text = messaging.message?.text || data.message?.text || data.text || '';
const message_id = messaging.message?.mid || data.message_id || '';
const is_echo = Boolean(messaging.message?.is_echo || data.message?.is_echo);

// Instagram sends our own outgoing replies back as echo events. Do not answer ourselves.
if (is_echo || (sender_id && page_id && sender_id === page_id)) {
  return [];
}

// Ignore reactions, delivery/read events, and empty/non-text messages.
if (!sender_id || !message_text.trim()) {
  return [];
}

return [
  {
    json: {
      sender_id,
      recipient_id,
      page_id,
      message_text: message_text.trim(),
      message_id,
      channel: 'instagram',
      brand: 'ErgeneAI'
    }
  }
];

const memoryResponse = $input.first().json;
const history = memoryResponse.data || [];
const originalData = $('01 Normalize Instagram DM').first().json;
let historyContext = '';
if (history.length > 0) {
  historyContext = '=== ONCEKI KONUSMA GECMISI ===\n';
  history.forEach(function(entry) {
    var role = entry.role === 'user' ? 'Musteri' : 'ErgeneAI';
    historyContext += role + ': ' + entry.message + '\n';
  });
  historyContext += '=== GECMIS SONU ===\n\n';
  historyContext += 'YUKARIDAKI gecmisi dikkate al. Ayni bilgileri tekrar sorma. Kaldigin yerden devam et.\n\n';
}
var enrichedPrompt = historyContext + 'MUSTERI MESAJI: ' + originalData.message_text;
return [{
  json: {
    sender_id: originalData.sender_id,
    recipient_id: originalData.recipient_id,
    page_id: originalData.page_id,
    message_text: originalData.message_text,
    message_id: originalData.message_id,
    channel: originalData.channel,
    brand: originalData.brand,
    enriched_prompt: enrichedPrompt,
    memory_count: history.length,
    memory_history: history
  }
}];

var aiOutput = $input.first().json;
var memoryHistory = $('Enrich Context with Memory').first().json.memory_history || [];
var reply = (aiOutput.output || '').toLowerCase();
var userMsg = ($('01 Normalize Instagram DM').first().json.message_text || '').toLowerCase();
var score = 'cold';
var signals = [];
var hotPatterns = ['randevu','gorusme','detayli bilgi','fiyat','ucret','hemen','acil','telefon','ulas','arayin','ariyorum','isterseniz','goruselim','toplanti','teklif'];
var warmPatterns = ['ilgileniyorum','istiyorum','dusunuyorum','guzel','harika','iyi olur','olabilir','belki','nasil oluyor','anlatir misin','bilgi verir','calisiyor','yardimci olur','faydali'];
for (var i = 0; i < hotPatterns.length; i++) {
  if (reply.includes(hotPatterns[i])) { signals.push('yankida_' + hotPatterns[i]); break; }
}
for (var i = 0; i < warmPatterns.length; i++) {
  if (reply.includes(warmPatterns[i])) { signals.push('ilgi_' + warmPatterns[i]); break; }
}
for (var i = 0; i < hotPatterns.length; i++) {
  if (userMsg.includes(hotPatterns[i])) { signals.push('kullanici_' + hotPatterns[i]); break; }
}
var hotCount = signals.filter(function(s) { return /randevu|fiyat|telefon|acil|teklif|gorus/.test(s); }).length;
var totalTurns = memoryHistory.length + 1;
if (hotCount > 0 || totalTurns >= 6) { score = 'hot'; }
else if (signals.length > 0 || totalTurns >= 3) { score = 'warm'; }
var aiReply = '';
if (typeof aiOutput.output === 'string') { aiReply = aiOutput.output; }
else if (aiOutput.output && typeof aiOutput.output === 'object') { aiReply = aiOutput.output.content || aiOutput.output.text || JSON.stringify(aiOutput.output); }
return [{
  json: {
    sender_id: $('01 Normalize Instagram DM').first().json.sender_id,
    recipient_id: $('01 Normalize Instagram DM').first().json.recipient_id,
    page_id: $('01 Normalize Instagram DM').first().json.page_id,
    message_text: $('01 Normalize Instagram DM').first().json.message_text,
    message_id: $('01 Normalize Instagram DM').first().json.message_id,
    channel: $('01 Normalize Instagram DM').first().json.channel,
    brand: $('01 Normalize Instagram DM').first().json.brand,
    output: aiReply,
    lead_score: score,
    lead_signals: signals.join(', '),
    conversation_turns: totalTurns
  }
}];

// Save user msg and AI reply to memory server
const scoreData = $input.first().json;
const senderId = scoreData.sender_id;
const userMsg = scoreData.message_text;
const aiReply = scoreData.output;

async function saveMem(sid, msg, role) {
  try {
    const resp = await this.helpers.request({
      method: 'POST',
      url: 'http://10.0.2.1:8899/memory/save',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ senderId: sid, message: msg, role: role }),
      json: true
    });
    return resp;
  } catch (err) {
    return { error: err.message };
  }
}

const userResult = await saveMem(senderId, userMsg, 'user');
const aiResult = await saveMem(senderId, aiReply, 'assistant');

return [{
  json: {
    ...scoreData,
    memory_save_user: userResult,
    memory_save_ai: aiResult
  }
}];

const scoreData = $input.first().json;
const senderId = scoreData.sender_id;
const userMsg = scoreData.message_text;
const aiReply = scoreData.output;
const leadScore = scoreData.lead_score;
const turnCount = scoreData.conversation_turns;
const signals = scoreData.lead_signals;

// Sadece yonlendirme yapildiysa bildirim gonder
const yonlendirmeKelimeleri = ['Bilal', '05520947032', 'ulasabilir', 'yonlendir', 'ilgilenecek', 'arayin', 'aramanizi', 'randevu'];
const yonlendirmeVar = yonlendirmeKelimeleri.some(function(k) {
  return aiReply.toLowerCase().includes(k.toLowerCase());
});

if (!yonlendirmeVar) {
  // Yonlendirme yok, bildirim gonderme - sadece datayi ilet
  return [{ json: scoreData }];
}

let emoji = '🔵';
if (leadScore === 'hot') emoji = '🔥';
else if (leadScore === 'warm') emoji = '🟡';
const NL = String.fromCharCode(10);
const report = [
  emoji + ' *Yeni Yonlendirme*',
  '',
  'Kullanici: ' + senderId,
  'Skor: ' + leadScore + ' | ' + turnCount + ' mesaj',
  '',
  'Musteri: ' + userMsg,
  'Yanit: ' + aiReply,
  '',
  'Sinyaller: ' + (signals || 'yok')
].join(NL);
try {
  var resp = await this.helpers.request({
    method: 'POST',
    url: 'https://api.telegram.org/bot8495399743:AAHUaoUp3lD_9cJ1b8fRj8p8dkCLT2_DWpw/sendMessage',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: '5506784207', text: report }),
    json: true
  });
  return [{ json: { ...scoreData, telegram_ok: true } }];
} catch (err) {
  return [{ json: { ...scoreData, telegram_err: err.message } }];
}

// Kullanici mesajinda intent tespiti
const text = ($json.text || $json.body || $json.prompt || "").toLowerCase();

let intent = "casual_chat";
let payload = {};

if (text.includes("kaydet") || text.includes("not et") || text.includes("hatirla") || text.includes("unutma")) {
  intent = "save_memory";
  payload = {
    content: $json.text || $json.body || $json.prompt || "",
    category: "genel"
  };
} else if (text.includes("ara") || text.includes("bul") || text.includes("ne yaziyordu") || text.includes("soylemistin")) {
  intent = "search_memory";
  payload = {
    sorgu: $json.text || $json.body || $json.prompt || "",
    limit: 3
  };
}

return [{
  json: {
    ...$json,
    _hermes: {
      intent: intent,
      payload: payload
    }
  }
}];
